        e.stopPropagation();
      }
    }, true);

    // (Opsional) nonaktifkan klik kanan
    window.addEventListener('contextmenu', function (e) {
      if (!isEditable(e.target)) {
        e.preventDefault();
      }
    }, true);
  })();
</script> 
