    box-shadow: 0 -5px 15px rgba(0, 0, 0, 0.5);
    z-index: 9999;
}

/* Tombol Dasar */
.footer-button {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: #c9d1d9; /* Warna teks abu-abu terang */
