    font-weight: 600;
    transition: color 0.3s ease;
    padding: 5px;
}

/* Label Teks */
.footer-label {
    margin-top: 4px;
}

/* Styling Ikon SVG */
.footer-icon {
    width: 24px;
    height: 24px;
}

/* --- Styling Unik (Neon Glow) --- */

/* 1. Login (Warna Biru/Ungu) */
.login-btn:hover {
