}
.login-btn:hover .footer-icon {
    stroke: #e93110;
    filter: drop-shadow(0 0 5px rgba(216, 150, 7, 0.8));
}

/* 2. Promo (Warna Paling Menonjol - Emas/Kuning) */
.promo-btn {
